USE P21Play;
SET NOCOUNT ON;
DECLARE @ShipmentFileId uniqueidentifier='f5c975af-1d81-5d36-9ff8-244fd38c9fc5';
DECLARE @ContainerBuildingUid int=900;
DECLARE @VesselReceiptsHdrUid int=762;
DECLARE @VesselReceiptsContainerUid int=762;
DECLARE @ContainerReceiptsHdrUid int=682;

SELECT
    receipt_build_rows = CONVERT(nvarchar(20), COUNT(*)),
    line_count = CONVERT(nvarchar(20), MAX(line_count)),
    total_qty = CONVERT(nvarchar(50), MAX(total_qty))
FROM P21Import.dbo.coats_mexico_shipment_receipt_build
WHERE shipment_file_id=@ShipmentFileId;

SELECT entity_name='container_building', row_count=CONVERT(nvarchar(20), COUNT(*)) FROM dbo.container_building WHERE container_building_uid=@ContainerBuildingUid;
SELECT entity_name='container_building_po', row_count=CONVERT(nvarchar(20), COUNT(*)), qty=CONVERT(nvarchar(50), SUM(po_container_unit_qty)) FROM dbo.container_building_po WHERE container_building_uid=@ContainerBuildingUid;
SELECT entity_name='vessel_receipts_hdr', row_count=CONVERT(nvarchar(20), COUNT(*)) FROM dbo.vessel_receipts_hdr WHERE vessel_receipts_hdr_uid=@VesselReceiptsHdrUid;
SELECT entity_name='vessel_receipts_container', row_count=CONVERT(nvarchar(20), COUNT(*)), row_status_flag=CONVERT(nvarchar(20), MAX(row_status_flag)) FROM dbo.vessel_receipts_container WHERE vessel_receipts_container_uid=@VesselReceiptsContainerUid;
SELECT entity_name='vessel_receipts_line', row_count=CONVERT(nvarchar(20), COUNT(*)), qty=CONVERT(nvarchar(50), SUM(container_qty_received)) FROM dbo.vessel_receipts_line WHERE vessel_receipts_hdr_uid=@VesselReceiptsHdrUid;
SELECT entity_name='container_receipts_hdr', row_count=CONVERT(nvarchar(20), COUNT(*)), row_status_flag=CONVERT(nvarchar(20), MAX(row_status_flag)) FROM dbo.container_receipts_hdr WHERE container_receipts_hdr_uid=@ContainerReceiptsHdrUid;
SELECT entity_name='container_receipts_line', row_count=CONVERT(nvarchar(20), COUNT(*)), qty=CONVERT(nvarchar(50), SUM(qty_received)), transfer_flag_null_count=CONVERT(nvarchar(20), SUM(CASE WHEN transfer_flag IS NULL THEN 1 ELSE 0 END)) FROM dbo.container_receipts_line WHERE container_receipts_hdr_uid=@ContainerReceiptsHdrUid;
SELECT staged_total=CONVERT(nvarchar(20), COUNT(*)), with_po_line_uid=CONVERT(nvarchar(20), SUM(CASE WHEN po_line_uid IS NOT NULL THEN 1 ELSE 0 END)), skipped_no_po_line=CONVERT(nvarchar(20), SUM(CASE WHEN po_line_uid IS NULL THEN 1 ELSE 0 END)) FROM P21Import.dbo.coats_mexico_shipment_pallet_line WHERE shipment_file_id=@ShipmentFileId;
